def generate_optimized():
    try:
        # Pad all stabilizers to max length
        max_len = max(len(s) for s in target_stabilizers)
        padded_stabs = [s.ljust(max_len, 'I') for s in target_stabilizers]
        
        # Create PauliString objects
        paulis = [stim.PauliString(s) for s in padded_stabs]
        
        # Synthesize using graph_state
        tableau = stim.Tableau.from_stabilizers(paulis, allow_underconstrained=True, allow_redundant=True)
        optimized = tableau.to_circuit(method="graph_state")
        
        # Post-process to replace RX with H and remove TICK
        final_circuit = stim.Circuit()
        for instruction in optimized:
            if instruction.name == "RX":
                # RX resets to |+>. From |0>, H does the same.
                final_circuit.append("H", instruction.targets_copy())
            elif instruction.name == "TICK":
                continue
            else:
                final_circuit.append(instruction)
        
        # Ensure we use up to 124 qubits to match baseline (if max index < 124)
        # Baseline uses 0..124.
        if final_circuit.num_qubits < 125:
             final_circuit.append("I", [124])
        
        print(final_circuit)
        
    except Exception as e:
        print(f"Error: {e}")

if __name__ == "__main__":
    generate_optimized()